# Sample data for seat changes
election_results = {
    'Conservative': {'lost': 17},
    'Labour': {'gained': 9},
    'Independents': {'gained': 6},
    'Liberal Democrats': {'gained': 2}
}

# Calculate net seat changes
total_change = sum(result['lost'] for result in election_results.values()) - sum(
    result.get('gained', 0) for result in election_results.values()
)

print("Seat Changes in 2019 Elections:")
for party, changes in election_results.items():
    for change_type, value in changes.items():
        print(f"{party} {change_type}: {value}")

print(f"\nTotal Net Seat Change: {total_change}")
